mapper.select:
SELECT PARTITION_NAME as partitionName,USED as used,DOMAIN_ID as domainId, UTILIZATION as utilization, SIZE as size
FROM TBL_DOMAIN_PARTITION_DETAIL WHERE 1=1

    AND DOMAIN_ID=${domainId}


    AND DOMAIN_ID in (${vmIds})


    AND HOST_POOL_ID =${hostPoolId}


    AND CLUSTER_ID =${clusterId}


    AND HOST_ID =${hostId}


    AND TIME > ${startTime}

AND TIME = (SELECT MAX(TIME) FROM TBL_DOMAIN_PARTITION_DETAIL)

SELECT TIME as time,PARTITION_NAME as partitionName,USED as used,DOMAIN_ID as domainId, UTILIZATION as utilization, SIZE as size
FROM TBL_DOMAIN_PARTITION_DETAIL WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND DOMAIN_ID=${domainId}

ORDER BY TIME ASC

SELECT PARTITION_NAME as partitionName,USED as used,DOMAIN_ID as domainId, UTILIZATION as utilization, SIZE as size, DOMAIN_ID as domainId, TITLE as title,vm.status as status FROM ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} vm, LEFT JOIN TBL_DOMAIN_PARTITION_DETAIL dpd ON vm.id = dpd.DOMAIN_ID WHERE dpd.DOMAIN_ID IS NOT NULL AND TIME = (SELECT MAX(TIME) FROM TBL_DOMAIN_PARTITION_DETAIL)
AND vm.title LIKE #{title}
AND vm.op_group_code LIKE #{operatorGroupCode}
ORDER BY DOMAIN_ID
